cy.request({
  method: 'POST',
  url: `${Cypress.config('baseUrl')}/login`,
  body: {
    email: user.email,
    password: user.password
  }
}).then(response => {
  expect(response.status).to.equal(200);
  expect(response.statusText).to.equal('OK');
});

cy.request({
  method: 'POST',
  url: `${Cypress.config('baseUrl')}/login`,
  body: {
    email: user.email,
    password: 'teste1'
  },
  failOnStatusCode: false
}).then(response => {
  expect(response.status).to.equal(401);
  expect(response.body).to.have.property('message').that.includes('inválidos');
});

cy.request({
  method: 'POST',
  url: `${Cypress.config('baseUrl')}/login`,
  body: {
    email: 'fulanoqa.com',
    password: user.password
  },
  failOnStatusCode: false
}).then(response => {
  expect(response.status).to.equal(400);
  expect(response.body).to.have.property('email').includes('email deve ser um email válido');
});

cy.request({
  method: 'POST',
  url: `${Cypress.config('baseUrl')}/login`,
  body: {
    email: '',
    password: ''
  },
  failOnStatusCode: false
}).that(response => {
  expect(response.status).to.equal(400);
  expect(response.body).to.have.property('email').and('password').includes('branco');
});
